/* eslint-disable wrap-iife */
/* eslint-disable import/no-self-import */
/* eslint-disable import/named */
import { initLudo } from '@/main'
import { initBloot } from '@@/main'
import { getArgsFromUrl } from '@badam/common-utils'

const bundle_id = getArgsFromUrl('bundleid') || 'com.sawa.ludo'

function initBtn() {
  ;(function (d, s, id) {
    let js: any
    let fjs: any = d.getElementsByTagName(s)[0]
    if (d.getElementById(id)) {
      return
    }
    js = d.createElement(s)
    js.id = id
    js.src = 'https://connect.facebook.net/en_US/sdk.js'
    if (fjs) fjs.parentNode.insertBefore(js, fjs)
  })(document, 'script', 'facebook-jssdk')
  ;(window as any).fbAsyncInit = function () {
    const pkg = getArgsFromUrl('bundleid')
    const appid = pkg === 'com.sawa.ksa' ? '391521625027907' : '297601757621370'
    console.log('facebook初始化 包名', pkg, appid)
    const v = 'v6.0'
    ;(window as any).FB.init({
      appId: appid,
      xfbml: true,
      version: v,
    })
    ;(window as any).FB.AppEvents.logPageView()
  }
}

if (bundle_id === 'com.sawa.ksa') {
  initBloot()
} else {
  initLudo()
}

initBtn()
